import java.io.*;

public class SecureCommandInjectionExample {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

            System.out.print("Enter a directory name to list files: ");
            String directory = reader.readLine();

            // Create a list to pass as the command and argument(s) to ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder("ls", directory);

            // Redirect error stream to output stream to capture any errors
            processBuilder.redirectErrorStream(true);

            Process process = processBuilder.start();

            BufferedReader processOutputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = processOutputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

